var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女と共にいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"태스크포스 영입 계약이라니, 흥미로운 제안입니다.","JPN":" タスクフォースへのスカウト契約とは、興味深い提案です。","ENG":"A TASKFORCE recruitment contract? What an interesting offer.","TWN":"特遣勢力的聘請契約，真是個有趣的提議。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"전 이미 관리국의 일원으로서 몸 담고 있긴 하지만…","JPN":" 私はすでに管理局の一員として携わっていますが……","ENG":"I'm already a member of the Administration, but…","TWN":"雖然我早已經是管理局的一員……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"존경하는 관리자님의 제안이라면 거절할 이유는 없겠죠.","JPN":" 尊敬する最高管理者様の提案なら断る理由はないでしょう。","ENG":"If it's an offer from Administrator, who I respect, I don't see any reason to decline.","TWN":"不過這是尊敬的管理者的提議，我沒有理由拒絕。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"...제가 관리자님을 존경하는 이유 말입니까?","JPN":" ……私が最高管理者様を尊敬する理由ですか？","ENG":"…Did you just ask why do I respect you, Administrator?","TWN":"……你問我為什麼會尊敬你?"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"모두가 알고 있듯, 관리자님께선 관리국을 세우고 세계의 질서를 바로잡은 분이기 때문이죠.","JPN":" 誰もが知っているように、最高管理者様は管理局を創設し世界の秩序を正した方だからです。","ENG":"As everyone knows, it's because you were the one who established the Administration and brought order to the world.","TWN":"眾所皆知，是你建立起管理局，導正世界的秩序。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"세상 사람들 대부분은 어떠한 대가를 바라고 행동합니다.","JPN":" 世の中の人々の大部分は何か代価を望んで行動します。","ENG":"Most people in this world hope for something in return for what they do.","TWN":"這世上的大多數人都是有所圖才會行動的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"돈, 명예, 자기증명, 그 무엇도 목표로 하지 않고 위업을 세우는 사람은 거의 없죠.","JPN":" お金、名誉、地位、何も目指さずに偉業を成し遂げる人などほとんど存在しません。","ENG":"There are very few people who achieve great things without seeking money, fame, or any other form of validation.","TWN":"金錢、名譽、名聲，很少能有人脫離這些目標而建功立業。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"하지만 관리자님은 세상을 구하기 위해 움직일 뿐, 어떤 대가나 타인의 이해조차 바라지 않으십니다.","JPN":" ですが、最高管理者様は世の中を救うために動くだけ、対価や他人の理解さえ望んでいらっしゃらないのです。","ENG":"But you act to save the world without expecting anything in return or wanting others to understand why you are doing so.","TWN":"但你的目的卻只是要拯救世界，並沒有期望任何回報或者他人的理解。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"지금에 이르러 대중들에게 모습을 드러내는 것도, 범인들이 이해하지 못할 계획의 일환일 뿐 결코 자신의 존재를 과시하기 위함은 아닐 거라 생각합니다.","JPN":" 今になって大衆の前に姿を現すのも、凡人が理解できない計画の一環であり、決して自分の存在を誇示するためではないと思います。","ENG":"I believe that exposing yourself to the public is simply a part of your plan that ordinary people will not understand, and is in no way an attempt to show off.","TWN":"我相信你現在選擇向大眾露面，也只是計畫的一部分，絕不是像普通人理解的一樣，是因為為炫耀自己。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"저는 대가를 바라보고 싸우는 범인일 뿐이며, 그런 대단한 사람이 될 수 없다는 걸 스스로도 잘 압니다.","JPN":" 私は対価を望んで戦う凡人であって、そんな大それた人にはなれないということを自分でもよくわかっています。","ENG":"I'm aware that I'm just an ordinary person who fights for something in return and that I will never become someone as great as you.","TWN":"我自己也只是一個別有所圖的凡人，我很清楚自己不可能成為那樣偉大的人物。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 그런 분을 위해 충성을 바칠 수는 있죠.","JPN":"しかし、そんな方のために忠誠を捧げることはできます。","ENG":"But what I can do is offer my loyalty to you.","TWN":"不過，我可以為這樣的人效忠。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"관리자님께서 제게 신뢰를 대가로 주셨으니, 저 역시 기꺼이 목숨 바쳐 따를 뿐입니다.","JPN":"最高管理者様が私に信頼を対価としてくださいましたので、私も喜んで命を捧げて従うだけです。","ENG":"Since you have given me your trust, I am willing to risk my life and follow you, Administrator.","TWN":"既然管理者願意信任我，我也願意為此赴湯蹈火。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그게 제가 이 자리에 있는 이유니까요.","JPN":" それが私がこの場にいる理由ですから。","ENG":"That is why I am here.","TWN":"那就是我在這裡的原因。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};